public class Solution {

    public static int[] solve(int[] testTup) {
        int length = testTup.length;
        if (length < 2) {
            return new int[0];
        }
        int[] result = new int[length - 1];
        for (int i = 0; i < length - 1; i++) {
            result[i] = testTup[i] + testTup[i + 1];
        }
        return result;
    }
}


